import screen from '@kyokuya/_shared/util/screen'
import ParticleEffectBubble from '@kyokuya/particle-bubble'
import type { IParticleEffectBubbleProps } from '@kyokuya/particle-bubble'
import { useParticleEffect2D } from '@kyokuya/particle-helper'
import { useBrightnessEffect, useIsMounted, useScrollProgress } from '@kyokuya/react-hooks'
import MenuOpenIcon from '@mui/icons-material/MenuOpen'
import Fab from '@mui/material/Fab'
import LinearProgress from '@mui/material/LinearProgress'
import { useLocation } from '@reach/router'
import cn from 'clsx'
import type { UIEventHandler } from 'react'
import React, { useCallback, useContext, useEffect, useRef } from 'react'
import siteMetadata from '@/config/site/metadata'
import { PostLayoutActionsType } from '../context/actions'
import { PostLayoutContext } from '../context/context'
import LayoutMain from './LayoutMain'
import LayoutSidebar from './LayoutSidebar'
import MagicPanel from './MagicPanel'

export interface LayoutProps {
  /**
   * HTML head elements.
   */
  head?: React.ReactNode
  /**
   * Main content.
   */
  content?: React.ReactNode
  /**
   * Navigation.
   */
  nav?: React.ReactNode
  /**
   * Footer content.
   */
  footer?: React.ReactNode
  /**
   * Url of pagination pages.
   */
  paginationUrl?: string
  /**
   * Handle scrolling event.
   */
  onScroll?: UIEventHandler
}

const bubbleOptions: IParticleEffectBubbleProps = {}

/**
 * Layout for blog layout.
 * @param props
 * @returns
 */
export function Layout(props: LayoutProps): React.ReactElement {
  const { author, copyright } = siteMetadata

  const { brightness, magicPanelVisible, dispatch } = useContext(PostLayoutContext)

  const { head, content, nav, footer, paginationUrl, onScroll } = props
  const containerRef = useRef<HTMLDivElement>(null)
  const scrollableContainerRef = useRef<HTMLDivElement>(null)

  const closeMagicPanel = useCallback<React.MouseEventHandler>(
    () =>
      dispatch({
        type: PostLayoutActionsType.TOGGLE_MAGIC_PANEL,
        payload: false,
      }),
    [dispatch],
  )

  const toggleMagicPanel = useCallback<React.MouseEventHandler>(
    e => {
      e.stopPropagation()
      dispatch({ type: PostLayoutActionsType.TOGGLE_MAGIC_PANEL })
    },
    [dispatch],
  )

  // Use particle effect when magic-panel is visible.
  useParticleEffect2D<IParticleEffectBubbleProps>(
    screen.lg ? containerRef : null,
    ParticleEffectBubble,
    bubbleOptions,
    magicPanelVisible,
  )

  useBrightnessEffect(brightness)

  // Scrollbar progress.
  const progress = useScrollProgress(screen.xs ? null : scrollableContainerRef)

  const location = useLocation()
  useEffect(() => {
    dispatch({ type: PostLayoutActionsType.TOGGLE_MAGIC_PANEL, payload: false })
  }, [location.pathname, dispatch])

  const isMounted = useIsMounted()
  return (
    <div
      ref={containerRef}
      className={cn('kyokuya-post__layout-container', {
        'kyokuya-post__layout-container--magic-panel-visible': magicPanelVisible,
        'page-preload': !isMounted,
      })}
      onClick={closeMagicPanel}
    >
      {head}
      <LinearProgress
        className="kyokuya-post__scroll-progressbar"
        color="primary"
        variant="determinate"
        value={progress * 100}
      />
      <Fab
        color="primary"
        size="large"
        className={cn('kyokuya-post__menu-button', {
          'kyokuya-post__menu-button--activated': magicPanelVisible,
        })}
        aria-label="toggle menu"
        onClick={toggleMagicPanel}
      >
        <MenuOpenIcon fontSize="large" />
      </Fab>
      <div
        ref={scrollableContainerRef}
        className="kyokuya-post__layout-scrollable-container"
        onScroll={onScroll}
      >
        <div className="kyokuya-post__layout-scrollable-wrapper">
          <LayoutSidebar
            authorName={author.name}
            authorMotto={author.motto}
            githubUrl={author.github}
            rssUrl={author.rss}
            homeUrl={author.home}
            paginationUrl={paginationUrl}
          />
          <MagicPanel nav={nav} />
          <LayoutMain
            copyrightDate={copyright.date}
            authorName={author.name}
            authorMotto={author.motto}
            content={content}
            footer={footer}
            showBackdrop={magicPanelVisible}
          />
        </div>
      </div>
    </div>
  )
}

Layout.displayName = 'Layout'
export default Layout
