import { useEffect } from 'react'

/**
 * Change dom filter.
 * @param brightness
 */
export function useBrightnessEffect(brightness: number): void {
  useEffect(() => {
    const html = document.documentElement
    if (html == null) return
    const filter = html.style.filter ?? ''

    if (/(brightness\s*\([^)]*\))/.test(filter)) {
      html.style.filter = filter.replace(/(brightness\s*\([^)]*\))/, `brightness(${brightness}%)`)
    } else {
      html.style.filter = (`brightness(${brightness}%) ` + filter).trim()
    }
  }, [brightness])
}

export default useBrightnessEffect
