import GithubIcon from '@kyokuya/icons/github'
import Link from '@kyokuya/react-link'
import RssFeedOutlinedIcon from '@mui/icons-material/RssFeedOutlined'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React, { useContext, useMemo } from 'react'
import avatarImgUrl from '@/resource/image/avatar.jpg'
import { PostLayoutActionsType } from '../context/actions'
import { PostLayoutContext } from '../context/context'
import type { MagicPanelType } from '../context/types'
import BrightnessSlider from './BrightnessSlider'

export interface LayoutSidebarProps {
  /**
   * Author's name.
   */
  authorName: string
  /**
   * Author's motto.
   */
  authorMotto: string
  /**
   * Github account url.
   */
  githubUrl: string
  /**
   * RSS feed url.
   */
  rssUrl: string
  /**
   * Home url
   */
  homeUrl: string
  /**
   * Url of pagination pages.
   */
  paginationUrl?: string
}

export const LayoutSidebar: React.FC<LayoutSidebarProps> = props => {
  const { authorName, authorMotto, githubUrl, rssUrl, paginationUrl, homeUrl } = props
  const { dispatch } = useContext(PostLayoutContext)

  const sidebar = useMemo(() => {
    const openPanel = (panelType: MagicPanelType): void =>
      dispatch({
        type: PostLayoutActionsType.ACTIVE_MAGIC_PANEL,
        payload: { panel: panelType },
      })

    const sidebarNav: React.ReactElement = (
      <React.Fragment>
        {paginationUrl && (
          <React.Fragment>
            <span key="pagination" className="kyokuya-post__layout-sidebar-nav-item">
              <Link url={paginationUrl}>文章</Link>
            </span>
            <span key="delimiter-1" className="kyokuya-post__layout-sidebar-nav-delimiter" />
          </React.Fragment>
        )}
        <span
          key="navigation"
          className="kyokuya-post__layout-sidebar-nav-item"
          onClick={() => openPanel('navigation')}
        >
          目录
        </span>
        <span key="delimiter-2" className="kyokuya-post__layout-sidebar-nav-delimiter" />
        <span
          key="search"
          className="kyokuya-post__layout-sidebar-nav-item"
          onClick={() => openPanel('search')}
        >
          检索
        </span>
        <span key="delimiter-3" className="kyokuya-post__layout-sidebar-nav-delimiter" />
        <span
          key="about-me"
          className="kyokuya-post__layout-sidebar-nav-item"
          onClick={() => openPanel('about-me')}
        >
          关于我
        </span>
      </React.Fragment>
    )

    return (
      <div className={cn('kyokuya-post__layout-sidebar', 'kyokuya-post__frosted-glass-panel')}>
        <div className="kyokuya-post__layout-sidebar-wrapper">
          <header className="kyokuya-post__layout-sidebar-header">
            <div className="kyokuya-post__layout-sidebar-overlay" />
            <BrightnessSlider className="kyokuya-post__layout-sidebar-brightness-slider" />
            <Link
              className="kyokuya-post__layout-sidebar-avatar"
              url={homeUrl}
              title="home"
              onClick={e => e.stopPropagation()}
            >
              <img alt="avatar" src={avatarImgUrl} />
            </Link>
            <h1 className="kyokuya-post__layout-sidebar-author">
              <span onClick={() => openPanel('about-me')}>{authorName}</span>
            </h1>
            <p className="kyokuya-post__layout-sidebar-motto">{authorMotto}</p>
          </header>
          <div className="kyokuya-post__layout-sidebar-main">
            <nav
              className={cn('hidden-xs', 'kyokuya-post__layout-sidebar-nav')}
              onClick={e => e.stopPropagation()}
            >
              {sidebarNav}
            </nav>
            <nav className="kyokuya-post__layout-sidebar-contact">
              <Link
                className="kyokuya-post__layout-sidebar-contact-item"
                url={githubUrl}
                title="github"
              >
                <GithubIcon />
              </Link>
              <Link className="kyokuya-post__layout-sidebar-contact-item" url={rssUrl} title="rss">
                <RssFeedOutlinedIcon />
              </Link>
            </nav>
            <nav
              className={cn('hidden-sm-plus', 'kyokuya-post__layout-sidebar-nav')}
              onClick={e => e.stopPropagation()}
            >
              {sidebarNav}
            </nav>
          </div>
        </div>
      </div>
    )
  }, [authorName, authorMotto, githubUrl, rssUrl, homeUrl, paginationUrl, dispatch])
  return sidebar
}

LayoutSidebar.propTypes = {
  authorName: PropTypes.string.isRequired,
  authorMotto: PropTypes.string.isRequired,
  githubUrl: PropTypes.string.isRequired,
  rssUrl: PropTypes.string.isRequired,
  homeUrl: PropTypes.string.isRequired,
  paginationUrl: PropTypes.string,
}

LayoutSidebar.displayName = 'KyokuyaLayoutPostLayoutSidebar'
export default LayoutSidebar
