import loadable from '@loadable/component'
import type { EcmaImport as IEcmaImport } from '@yozora/ast'
import { YozoraImagePreviewer, YozoraMarkdownContextProvider } from '@yozora/react-markdown'
import type { IYozoraMarkdownContextProviderProps } from '@yozora/react-markdown'
import React from 'react'
import { useCodeRunners } from './code-runner/runner'
import { defaultCustomRendererMap } from './renderer'

const Viewer = loadable(() => import('react-viewer')) as any

export interface MarkdownContextProviderProps extends IYozoraMarkdownContextProviderProps {
  /**
   * Dynamic ecma imports.
   */
  ecmaImports: IEcmaImport[]
}

export function MarkdownContextProvider(props: MarkdownContextProviderProps): React.ReactElement {
  const {
    ecmaImports,
    children,
    customRendererMap,
    codeRunners: customCodeRunners,
    preferLinenos = false,
    ...restProps
  } = props

  const _codeRunners = useCodeRunners(ecmaImports)
  return (
    <YozoraMarkdownContextProvider
      {...restProps}
      preferLinenos={preferLinenos}
      codeRunners={customCodeRunners ?? _codeRunners}
      customRendererMap={customRendererMap ?? defaultCustomRendererMap}
    >
      {children}
      <YozoraImagePreviewer ImageViewer={Viewer} />
    </YozoraMarkdownContextProvider>
  )
}

export default MarkdownContextProvider
