import { useDeepCompareMemo } from '@guanghechen/react-hooks'
import PropTypes from 'prop-types'
import React, { useEffect, useReducer } from 'react'
import { PostLayoutActionsType } from './actions'
import { PostLayoutContext } from './context'
import reducer from './reducer'
import { initializePostLayoutContextData, usePostLayoutContextDataChangeEffect } from './state'
import type { IPostItem } from './types'

export interface PostLayoutContextProviderProps {
  /**
   *
   */
  posts: ReadonlyArray<IPostItem>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const PostLayoutContextProvider: React.FC<PostLayoutContextProviderProps> = props => {
  const { posts: initialPosts, children } = props

  const { tags, posts } = useDeepCompareMemo(() => {
    const tagSet: Set<string> = new Set()
    for (const post of initialPosts) {
      for (const tag of post.tags) tagSet.add(tag)
    }
    const tags: ReadonlyArray<string> = Array.from(tagSet).sort()
    return { tags, posts: initialPosts.slice() }
  }, [initialPosts])

  const [contextData, dispatch] = useReducer(
    reducer,
    { posts, tags },
    initializePostLayoutContextData,
  )

  // save data
  usePostLayoutContextDataChangeEffect(contextData)

  useEffect(() => {
    dispatch({
      type: PostLayoutActionsType.REFRESH_STATIC_DATA,
      payload: { tags, posts },
    })
  }, [tags, posts])

  return (
    <PostLayoutContext.Provider value={{ ...contextData, dispatch }}>
      {children}
    </PostLayoutContext.Provider>
  )
}

PostLayoutContextProvider.propTypes = {
  posts: PropTypes.array.isRequired,
  children: PropTypes.node.isRequired,
}

PostLayoutContextProvider.displayName = 'KyokuyaLayoutPostContextProvider'
export default PostLayoutContextProvider
